        private static string BuildSelectClause(string selectParam, HashSet<string> allowedColumns)
        {
            if (string.IsNullOrWhiteSpace(selectParam))
            {
                return "*";
            }

            var requestedColumns = selectParam.Split(',', StringSplitOptions.RemoveEmptyEntries)
                .Select(c => c.Trim())
                .Where(c => allowedColumns.Contains(c))
                .Select(c => $"[{c}]")
                .ToList();

            return requestedColumns.Count > 0 ? string.Join(", ", requestedColumns) : "*";
        }

        private static string BuildOrderByClause(string orderByParam, string sortDirParam, HashSet<string> allowedColumns)
        {
            if (string.IsNullOrWhiteSpace(orderByParam))
