            }

            string sortDirection = "ASC";
            if (!string.IsNullOrWhiteSpace(sortDirParam) && AllowedSortDirections.Contains(sortDirParam))
            {
                sortDirection = sortDirParam.ToUpperInvariant();
            }

            return $"[{orderByParam}] {sortDirection}";
        }

        private static string BuildGroupByClause(string groupByParam, HashSet<string> allowedColumns)
        {
