            var groupColumns = groupByParam.Split(',', StringSplitOptions.RemoveEmptyEntries)
                .Select(c => c.Trim())
                .Where(c => allowedColumns.Contains(c))
                .Select(c => $"[{c}]")
                .ToList();

            return groupColumns.Count > 0 ? string.Join(", ", groupColumns) : null;
        }

        /// <summary>
