                        string paramName = $"@p{paramIndex++}";
                        conditions.Add($"{escapedColumn} = {paramName}");
                        parameters.Add(new SqlParameter(paramName, value ?? (object)DBNull.Value));
                        break;
                    }
                    case "neq":
                    {
                        string paramName = $"@p{paramIndex++}";
                        conditions.Add($"{escapedColumn} <> {paramName}");
                        parameters.Add(new SqlParameter(paramName, value ?? (object)DBNull.Value));
                        break;
                    }
                    case "gt":
                    {
                        string paramName = $"@p{paramIndex++}";
                        conditions.Add($"{escapedColumn} > {paramName}");
                        parameters.Add(CreateTypedParameter(paramName, value));
                        break;
                    }
                    case "gte":
                    {
                        string paramName = $"@p{paramIndex++}";
                        conditions.Add($"{escapedColumn} >= {paramName}");
                        parameters.Add(CreateTypedParameter(paramName, value));
                        break;
                    }
                    case "lt":
                    {
                        string paramName = $"@p{paramIndex++}";
                        conditions.Add($"{escapedColumn} < {paramName}");
                        parameters.Add(CreateTypedParameter(paramName, value));
                        break;
                    }
                    case "lte":
                    {
                        string paramName = $"@p{paramIndex++}";
                        conditions.Add($"{escapedColumn} <= {paramName}");
                        parameters.Add(CreateTypedParameter(paramName, value));
                        break;
                    }
                    case "like":
                    {
                        string paramName = $"@p{paramIndex++}";
                        conditions.Add($"{escapedColumn} LIKE {paramName}");
                        parameters.Add(new SqlParameter(paramName, value));
                        break;
                    }
                    case "in":
                    {
                        if (string.IsNullOrWhiteSpace(value))
                        {
                            return new FilterResult { Error = $"'in' operator requires comma-separated values for column '{columnName}'." };
                        }

                        var inValues = value.Split(',', StringSplitOptions.RemoveEmptyEntries);
                        var inParamNames = new List<string>();
                        foreach (var inVal in inValues)
                        {
                            string paramName = $"@p{paramIndex++}";
                            inParamNames.Add(paramName);
                            parameters.Add(new SqlParameter(paramName, inVal.Trim()));
                        }
                        conditions.Add($"{escapedColumn} IN ({string.Join(", ", inParamNames)})");
                        break;
                    }
                    case "between":
                    {
                        if (string.IsNullOrWhiteSpace(value) || !value.Contains(','))
                        {
                            return new FilterResult
