                        }

                        var betweenParts = value.Split(',', 2);
                        string paramLow = $"@p{paramIndex++}";
                        string paramHigh = $"@p{paramIndex++}";
                        conditions.Add($"{escapedColumn} BETWEEN {paramLow} AND {paramHigh}");
                        parameters.Add(CreateTypedParameter(paramLow, betweenParts[0].Trim()));
                        parameters.Add(CreateTypedParameter(paramHigh, betweenParts[1].Trim()));
