                        conditions.Add($"{escapedColumn} IS NULL");
                        break;
                    }
                    case "isnotnull":
                    {
                        conditions.Add($"{escapedColumn} IS NOT NULL");
                        break;
                    }
                }
            }

            return new FilterResult
            {
                WhereClause = conditions.Count > 0 ? string.Join(" AND ", conditions) : null,
                Parameters = parameters
