        private static SqlParameter CreateTypedParameter(string name, string value)
        {
            // Try to infer type for proper comparison
            if (decimal.TryParse(value, out decimal decimalVal))
            {
                return new SqlParameter(name, SqlDbType.Decimal) { Value = decimalVal };
            }

            if (DateTime.TryParse(value, out DateTime dateVal))
            {
                return new SqlParameter(name, SqlDbType.DateTime2) { Value = dateVal };
            }

            return new SqlParameter(name, value);
        }

        private static string BuildSqlQuery(string tableName, string selectClause, string whereClause,
            string orderByClause, string groupByClause, int? top, int? offset)
        {
            var parts = new List<string>();

            // SELECT
            string topClause = "";
            if (top.HasValue && !offset.HasValue)
            {
                topClause = $"TOP ({top.Value}) ";
            }

            parts.Add($"SELECT {topClause}{selectClause}");

            // FROM - table name is validated against whitelist, so bracket-escaping is safe
            parts.Add($"FROM [{tableName}]");

            // WHERE
            if (!string.IsNullOrWhiteSpace(whereClause))
            {
                parts.Add($"WHERE {whereClause}");
            }

            // GROUP BY
            if (!string.IsNullOrWhiteSpace(groupByClause))
            {
                parts.Add($"GROUP BY {groupByClause}");
            }

            // ORDER BY (required for OFFSET-FETCH)
            if (!string.IsNullOrWhiteSpace(orderByClause))
            {
                parts.Add($"ORDER BY {orderByClause}");
            }
            else if (offset.HasValue)
            {
                // Default ordering required for OFFSET
                parts.Add("ORDER BY (SELECT NULL)");
            }

            // OFFSET-FETCH for pagination
            if (offset.HasValue)
            {
                parts.Add($"OFFSET {offset.Value} ROWS");
                if (top.HasValue)
                {
                    parts.Add($"FETCH NEXT {top.Value} ROWS ONLY");
                }
            }

            return string.Join(" ", parts);
        }

        private static async Task<List<Dictionary<string, object>>> ExecuteQueryAsync(
            string connectionString, string sql, List<SqlParameter> parameters, ILogger log)
        {
            var results = new List<Dictionary<string, object>>();

            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();

                using (var command = new SqlCommand(sql, connection))
                {
                    command.CommandTimeout = 30;

                    if (parameters != null)
                    {
                        foreach (var param in parameters)
                        {
                            command.Parameters.Add(param);
                        }
                    }

                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                string colName = reader.GetName(i);
                                object val = reader.IsDBNull(i) ? null : reader.GetValue(i);
                                row[colName] = val;
                            }
                            results.Add(row);
                        }
                    }
                }
            }

            log.LogInformation("Query returned {Count} rows.", results.Count);
            return results;
        }

